.radex-legacy .content-img{
    width: 100%;
    aspect-ratio: 16 / 9;
    object-fit: cover;
    border-radius: 16px;
    display: block;
    margin: 40px 0;
  }.radex-legacy .content-img-wrap{
    padding: 0 var(--section-px, 80px);
    max-width: 1200px;
    margin: 0 auto;
  }.radex-legacy .trust-list{
    list-style: none;
    padding: 0;
    margin: 28px 0 0;
    display: flex;
    flex-direction: column;
    gap: 16px;
  }.radex-legacy .trust-list li{
    display: flex;
    align-items: flex-start;
    gap: 14px;
    font-size: 15px;
    color: var(--text-light);
    line-height: 1.55;
  }.radex-legacy .trust-list li .tl-icon{
    width: 36px;
    height: 36px;
    background: var(--gold-pale);
    border-radius: 10px;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
  }.radex-legacy .trust-list li strong{
    display: block;
    color: var(--navy);
    font-weight: 700;
    margin-bottom: 2px;
  }.radex-legacy .gewerk-grid{
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 20px;
    margin-top: 32px;
  }.radex-legacy .gewerk-card{
    background: var(--white);
    border: 1px solid var(--light-gray);
    border-radius: 14px;
    padding: 24px;
  }.radex-legacy .gewerk-card h3{
    font-size: 16px;
    font-weight: 700;
    color: var(--navy);
    margin: 0 0 10px;
  }.radex-legacy .gewerk-card p{
    font-size: 14px;
    color: var(--text-light);
    line-height: 1.6;
    margin: 0;
  }.radex-legacy .gewerk-icon{
    width: 40px;
    height: 40px;
    background: var(--gold-pale);
    border-radius: 10px;
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 14px;
  }.radex-legacy .phase-list{
    counter-reset: phase;
    list-style: none;
    padding: 0;
    margin: 28px 0 0;
    display: flex;
    flex-direction: column;
    gap: 20px;
  }.radex-legacy .phase-list li{
    counter-increment: phase;
    display: flex;
    align-items: flex-start;
    gap: 16px;
    font-size: 15px;
    color: var(--text-light);
    line-height: 1.6;
  }.radex-legacy .phase-list li::before{
    content: counter(phase);
    width: 36px;
    height: 36px;
    background: var(--navy);
    color: #fff;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 700;
    font-size: 14px;
    flex-shrink: 0;
  }.radex-legacy .phase-list li strong{
    display: block;
    color: var(--navy);
    font-weight: 700;
    margin-bottom: 2px;
  }.radex-legacy .info-box{
    background: var(--gold-pale);
    border-left: 4px solid var(--gold);
    border-radius: 0 12px 12px 0;
    padding: 20px 24px;
    margin: 28px 0;
    font-size: 15px;
    color: var(--text);
    line-height: 1.65;
  }.radex-legacy .bullet-list{
    list-style: none;
    padding: 0;
    margin: 20px 0 0;
    display: flex;
    flex-direction: column;
    gap: 10px;
  }.radex-legacy .bullet-list li{
    display: flex;
    align-items: flex-start;
    gap: 10px;
    font-size: 15px;
    color: var(--text-light);
    line-height: 1.6;
  }.radex-legacy .bullet-list li::before{
    content: '';
    width: 7px;
    height: 7px;
    background: var(--gold);
    border-radius: 50%;
    flex-shrink: 0;
    margin-top: 7px;
  }@media (max-width: 860px){.radex-legacy .gewerk-grid{ grid-template-columns: repeat(2, 1fr); }
  }@media (max-width: 540px){.radex-legacy .gewerk-grid{ grid-template-columns: 1fr; }.radex-legacy .content-img-wrap{ padding: 0 20px; }
  }.radex-legacy .cta-form-wrap{
    background: var(--navy-dark);
    padding: 80px 48px;
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 64px;
    align-items: start;
  }.radex-legacy .cta-form-left h2{ color: var(--white); margin-bottom: 16px; }.radex-legacy .cta-form-left p{ color: rgba(255,255,255,0.75); font-size: 16px; line-height: 1.7; margin-bottom: 28px; }.radex-legacy .cta-form-left .cta-direct{ display: flex; flex-direction: column; gap: 12px; }.radex-legacy .cta-form-left .cta-direct a{
    color: rgba(255,255,255,0.8); font-size: 15px;
    text-decoration: none; display: flex; align-items: center; gap: 10px;
    transition: color 0.2s;
  }.radex-legacy .cta-form-left .cta-direct a:hover{ color: var(--white); }.radex-legacy .cta-form-right{ background: var(--white); border-radius: 14px; padding: 32px; }.radex-legacy .cta-form-right h3{ font-size: 18px; font-weight: 700; color: var(--navy); margin-bottom: 20px; }.radex-legacy .cta-form-right .form-row{ display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }.radex-legacy .cta-form-right .form-field{ display: flex; flex-direction: column; gap: 6px; margin-bottom: 12px; }.radex-legacy .cta-form-right label{
    font-size: 12px; font-weight: 600; color: var(--text-light);
    text-transform: uppercase; letter-spacing: 0.05em;
  }.radex-legacy .cta-form-right input, .radex-legacy .cta-form-right textarea{
    border: 1px solid var(--light-gray);
    border-radius: 8px;
    padding: 11px 14px;
    font-family: inherit;
    font-size: 14px;
    color: var(--text);
    background: var(--off-white);
    transition: border-color 0.2s;
    outline: none; 
    width: 100%;
    box-sizing: border-box;
  }.radex-legacy .cta-form-right input:focus, .radex-legacy .cta-form-right textarea:focus{ border-color: var(--navy); background: var(--white); }.radex-legacy .cta-form-right textarea{ resize: vertical; min-height: 90px; }.radex-legacy .cta-form-right .form-submit{ width: 100%; margin-top: 4px; font-size: 15px; padding: 13px; border: none; cursor: pointer; }.radex-legacy .cta-form-dsgvo{ display: flex; align-items: flex-start; gap: 10px; margin-bottom: 4px; }.radex-legacy .cta-form-dsgvo input[type="checkbox"]{ width: 16px; height: 16px; flex-shrink: 0; margin-top: 2px; accent-color: var(--navy); cursor: pointer; }.radex-legacy .cta-form-dsgvo label{ font-size: 12px; color: var(--text-light); line-height: 1.55; text-transform: none; letter-spacing: 0; font-weight: 400; }.radex-legacy .cta-form-dsgvo a{ color: var(--navy); text-decoration: underline; }.radex-legacy .cta-form-privacy{ font-size: 12px; color: var(--text-light); margin: 6px 0 0; line-height: 1.6; }.radex-legacy .cta-form-privacy a{ color: var(--navy); text-decoration: underline; }@media (max-width: 900px){.radex-legacy .cta-form-wrap{ grid-template-columns: 1fr; gap: 36px; padding: 48px 28px; }.radex-legacy .cta-form-right .form-row{ grid-template-columns: 1fr; }
  }@media (max-width: 560px){.radex-legacy .cta-form-wrap{ padding: 40px 20px; }
  }.radex-legacy #cookie-banner{
  position: fixed;
  bottom: 24px; left: 50%;
  transform: translateX(-50%);
  width: calc(100% - 48px);
  max-width: 760px;
  background: var(--white);
  border: 1px solid var(--light-gray);
  border-radius: 14px;
  box-shadow: 0 8px 40px rgba(27,58,107,0.14);
  padding: 24px 28px;
  z-index: 9000;
  display: flex;
  align-items: center;
  gap: 24px;
  flex-wrap: wrap;
}.radex-legacy #cookie-banner .cb-text{ flex: 1; min-width: 220px; }.radex-legacy #cookie-banner .cb-text p{ font-size: 13.5px; color: var(--text-light); line-height: 1.6; margin: 0; }.radex-legacy #cookie-banner .cb-actions{ display: flex; gap: 10px; flex-wrap: wrap; align-items: center; }.radex-legacy .cb-btn{
  border: none; cursor: pointer; border-radius: 8px;
  font-family: inherit; font-size: 13px; font-weight: 600;
  padding: 10px 18px; transition: opacity 0.2s, background 0.2s;
  white-space: nowrap;
}.radex-legacy .cb-btn:hover{ opacity: 0.85; }.radex-legacy .cb-btn--accept{ background: var(--gold); color: var(--white); }.radex-legacy .cb-btn--reject{ background: var(--off-white); color: var(--text); border: 1px solid var(--light-gray); }.radex-legacy .cb-btn--settings{ background: transparent; color: var(--text-light); padding: 10px 12px; }.radex-legacy .cm-overlay{
  position: fixed; inset: 0;
  background: rgba(0,0,0,0.45);
  z-index: 9001;
}.radex-legacy .cm-box{
  position: fixed; top: 50%; left: 50%;
  transform: translate(-50%, -50%);
  background: var(--white);
  border-radius: 16px;
  padding: 36px;
  width: calc(100% - 48px);
  max-width: 480px;
  z-index: 9002;
  box-shadow: 0 20px 60px rgba(27,58,107,0.18);
}.radex-legacy .cm-box h3{ font-size: 20px; font-weight: 700; color: var(--navy); margin-bottom: 8px; }.radex-legacy .cm-intro{ font-size: 14px; color: var(--text-light); margin-bottom: 24px; }.radex-legacy .cm-category{
  border: 1px solid var(--light-gray);
  border-radius: 10px;
  padding: 16px 18px;
  margin-bottom: 12px;
}.radex-legacy .cm-category-header{
  display: flex; justify-content: space-between; align-items: center;
  margin-bottom: 6px;
}.radex-legacy .cm-category-header strong{ font-size: 15px; color: var(--text); }.radex-legacy .cm-category p{ font-size: 13px; color: var(--text-light); margin: 0; }.radex-legacy .cm-badge{
  font-size: 11px; font-weight: 600; color: var(--gold);
  background: var(--gold-pale); border-radius: 20px;
  padding: 2px 8px; margin-left: 8px;
}.radex-legacy .cm-toggle{ display: inline-block; position: relative; width: 40px; height: 22px; flex-shrink: 0; }.radex-legacy .cm-toggle input{ opacity: 0; width: 0; height: 0; }.radex-legacy .cm-toggle span{
  position: absolute; inset: 0; background: var(--light-gray);
  border-radius: 22px; cursor: pointer; transition: background 0.2s;
}.radex-legacy .cm-toggle span::before{
  content: ""; position: absolute;
  width: 16px; height: 16px; border-radius: 50%;
  background: var(--white); left: 3px; top: 3px;
  transition: transform 0.2s;
  box-shadow: 0 1px 4px rgba(0,0,0,0.15);
}.radex-legacy .cm-toggle input:checked + span{ background: var(--gold); }.radex-legacy .cm-toggle input:checked + span::before{ transform: translateX(18px); }.radex-legacy .cm-toggle--locked span{ background: var(--gold); cursor: default; }.radex-legacy .cm-toggle--locked span::before{ transform: translateX(18px); }.radex-legacy .cm-actions{ display: flex; gap: 10px; margin-top: 24px; justify-content: flex-end; flex-wrap: wrap; }@media (max-width: 560px){.radex-legacy #cookie-banner{ bottom: 0; left: 0; right: 0; transform: none; width: 100%; border-radius: 14px 14px 0 0; flex-direction: column; gap: 16px; }.radex-legacy .cm-box{ padding: 28px 20px; }.radex-legacy .cm-actions{ justify-content: stretch; }.radex-legacy .cm-actions .cb-btn{ flex: 1; text-align: center; }
}

